BEGIN;

CREATE TABLE IF NOT EXISTS dasha_periods (
  id            UUID         PRIMARY KEY DEFAULT gen_random_uuid(),
  chart_id      TEXT         NOT NULL,
  system        TEXT         NOT NULL,                          -- 'vimshottari'|'yogini'|'chara'|'narayana'|'kp'
  planet        TEXT         NOT NULL,                          -- 'Sun'|'Moon'|'Mars'|...
  level         TEXT         NOT NULL CHECK (level IN ('M','A','P','S')),  -- M=Mahadasha, A=Antar, P=Pratyantar, S=Sookshma
  start_date    DATE         NOT NULL,
  end_date      DATE         NOT NULL,
  duration_days INTEGER      NOT NULL,
  parent_md     TEXT,
  parent_ad     TEXT,
  computed_by   TEXT         NOT NULL,
  ayanamsha     TEXT         NOT NULL,
  created_at    TIMESTAMPTZ  NOT NULL DEFAULT now(),
  UNIQUE (chart_id, system, level, start_date, planet)
);

CREATE INDEX IF NOT EXISTS idx_dasha_periods_chart_system ON dasha_periods(chart_id, system);
CREATE INDEX IF NOT EXISTS idx_dasha_periods_dates ON dasha_periods(start_date, end_date);

COMMIT;
